mapper.select:
select count(1) from operation_logs
and ( operator_name like concat('%', #{keyword}, '%') or operation_module like concat('%', #{keyword}, '%') or operation_content like concat('%', #{keyword}, '%') )
and operation_type = #{operationType}

select id, operate_time, operator_name, operation_module, operation_type, operation_content, ip
from operation_logs


    and (
      operator_name like concat('%', #{keyword}, '%')
      or operation_module like concat('%', #{keyword}, '%')
      or operation_content like concat('%', #{keyword}, '%')
    )


    and operation_type = #{operationType}


order by id desc
limit #{pageSize} offset #{offset}
